logger = logging.getLogger(__name__)


class RabbitMQConnection:
    """Base class for RabbitMQ connections with retry logic."""

    def __init__(
        self,
        host: str = 'localhost',
        port: int = 5672,
        username: str = 'guest',
        password: str = 'guest',
        virtual_host: str = '/',
        heartbeat: int = 600,
        connection_attempts: int = 3,
        retry_delay: int = 5,
    ):
        self.host = host
        self.port = port
        self.credentials = pika.PlainCredentials(username, password)
        self.connection_params = pika.ConnectionParameters(
            host=self.host,
            port=self.port,
            virtual_host=virtual_host,
            credentials=self.credentials,
            heartbeat=heartbeat,
            connection_attempts=connection_attempts,
            retry_delay=retry_delay,
        )
        self.connection: Optional[pika.BlockingConnection] = None
        self.channel: Optional[pika.channel.Channel] = None

    def connect(self):
        """Establish connection to RabbitMQ server."""
        try:
            self.connection = pika.BlockingConnection(self.connection_params)
            self.channel = self.connection.channel()
            logger.info(f"Connected to RabbitMQ at {self.host}:{self.port}")
        except pika.exceptions.AMQPConnectionError as e:
            logger.error(f"Failed to connect to RabbitMQ: {e}")
            raise

    def close(self):
        """Close the connection gracefully."""
        if self.connection and not self.connection.is_closed:
            self.connection.close()
            logger.info("Connection to RabbitMQ closed.")

    def ensure_connection(self):
        """Ensure the connection is open, reconnect if necessary."""
        if self.connection is None or self.connection.is_closed:
            logger.info("Reconnecting to RabbitMQ...")
            self.connect()


class TaskPublisher(RabbitMQConnection):
    """Publishes task messages to RabbitMQ queues."""

    def __init__(
        self,
        queue_name: str = 'task_queue',
        exchange_name: str = 'task_exchange',
        routing_key: str = 'task',
        durable: bool = True,
        **kwargs,
    ):
        super().__init__(**kwargs)
        self.queue_name = queue_name
        self.exchange_name = exchange_name
        self.routing_key = routing_key
        self.durable = durable

    def setup(self):
        """Set up exchange and queue."""
        self.ensure_connection()

        # Declare a direct exchange
        self.channel.exchange_declare(
            exchange=self.exchange_name,
            exchange_type='direct',
            durable=self.durable,
        )

        # Declare the queue
        self.channel.queue_declare(
            queue=self.queue_name,
            durable=self.durable,
            arguments={
                'x-message-ttl': 86400000,  # 24 hours TTL
                'x-max-length': 100000,      # Max 100k messages
            },
        )

        # Bind queue to exchange
        self.channel.queue_bind(
            exchange=self.exchange_name,
            queue=self.queue_name,
            routing_key=self.routing_key,
        )

        # Enable publisher confirms
        self.channel.confirm_delivery()

        logger.info(
            f"Publisher setup complete. Exchange: {self.exchange_name}, "
            f"Queue: {self.queue_name}, Routing Key: {self.routing_key}"
        )

    def publish_task(
        self,
        task_type: str,
        payload: Dict[str, Any],
        priority: int = 0,
        correlation_id: Optional[str] = None,
    ) -> str:
        """
        Publish a task message to the queue.

        Args:
            task_type: The type/name of the task.
            payload: The task data/payload.
            priority: Message priority (0-9).
            correlation_id: Optional correlation ID for tracking.

        Returns:
            The task_id of the published message.
        """
        self.ensure_connection()

        task_id = correlation_id or str(uuid.uuid4())

        message = {
            'task_id': task_id,
            'task_type': task_type,
            'payload': payload,
            'created_at': datetime.utcnow().isoformat(),
            'retry_count': 0,
            'max_retries': 3,
        }

        properties = pika.BasicProperties(
            delivery_mode=2,  # Persistent message
            content_type='application/json',
            correlation_id=task_id,
            priority=priority,
            timestamp=int(time.time()),
            headers={
                'task_type': task_type,
                'version': '1.0',
            },
        )

        try:
            self.channel.basic_publish(
                exchange=self.exchange_name,
                routing_key=self.routing_key,
                body=json.dumps(message),
                properties=properties,
                mandatory=True,
            )
            logger.info(
                f"Published task: {task_id} | Type: {task_type} | "
                f"Priority: {priority}"
            )
            return task_id
        except pika.exceptions.UnroutableError:
            logger.error(f"Message {task_id} was returned (unroutable).")
            raise
        except pika.exceptions.NackError:
            logger.error(f"Message {task_id} was nacked by the broker.")
            raise

    def publish_batch(
        self,
        tasks: list,
    ) -> list:
        """
        Publish a batch of tasks.

        Args:
            tasks: List of dicts with keys: task_type, payload, priority (optional).

        Returns:
            List of task_ids.
        """
        task_ids = []
        for task in tasks:
            task_id = self.publish_task(
                task_type=task['task_type'],
                payload=task['payload'],
                priority=task.get('priority', 0),
            )
            task_ids.append(task_id)
        return task_ids


class TaskConsumer(RabbitMQConnection):
    """Consumes and processes task messages from RabbitMQ queues."""

    def __init__(
        self,
        queue_name: str = 'task_queue',
        exchange_name: str = 'task_exchange',
        routing_key: str = 'task',
        prefetch_count: int = 1,
        durable: bool = True,
        dead_letter_exchange: str = 'dlx_exchange',
        dead_letter_queue: str = 'dead_letter_queue',
        **kwargs,
    ):
        super().__init__(**kwargs)
        self.queue_name = queue_name
        self.exchange_name = exchange_name
        self.routing_key = routing_key
        self.prefetch_count = prefetch_count
        self.durable = durable
        self.dead_letter_exchange = dead_letter_exchange
        self.dead_letter_queue = dead_letter_queue
        self.task_handlers: Dict[str, Callable] = {}
        self._consuming = False

    def register_handler(self, task_type: str, handler: Callable):
        """
        Register a handler function for a specific task type.

        Args:
            task_type: The task type string.
            handler: Callable that takes (task_id, payload) and returns a result.
        """
        self.task_handlers[task_type] = handler
        logger.info(f"Registered handler for task type: {task_type}")

    def setup(self):
        """Set up exchange, queues, and dead letter exchange."""
        self.ensure_connection()

        # Set up dead letter exchange and queue
        self.channel.exchange_declare(
            exchange=self.dead_letter_exchange,
            exchange_type='direct',
            durable=True,
        )
        self.channel.queue_declare(
            queue=self.dead_letter_queue,
            durable=True,
        )
        self.channel.queue_bind(
            exchange=self.dead_letter_exchange,
            queue=self.dead_letter_queue,
            routing_key='dead_letter',
        )

        # Declare main exchange
        self.channel.exchange_declare(
            exchange=self.exchange_name,
            exchange_type='direct',
            durable=self.durable,
        )

        # Declare main queue with dead letter configuration
        self.channel.queue_declare(
            queue=self.queue_name,
            durable=self.durable,
            arguments={
                'x-message-ttl': 86400000,
                'x-max-length': 100000,
                'x-dead-letter-exchange': self.dead_letter_exchange,
                'x-dead-letter-routing-key': 'dead_letter',
            },
        )

        # Bind main queue
        self.channel.queue_bind(
            exchange=self.exchange_name,
            queue=self.queue_name,
            routing_key=self.routing_key,
        )

        # Set QoS / prefetch
        self.channel.basic_qos(prefetch_count=self.prefetch_count)

        logger.info(
            f"Consumer setup complete. Queue: {self.queue_name}, "
            f"Prefetch: {self.prefetch_count}"
        )

    def _on_message(self, channel, method, properties, body):
        """
        Callback for processing received messages.
        """
        task_id = None
        try:
            message = json.loads(body)
            task_id = message.get('task_id', 'unknown')
            task_type = message.get('task_type', 'unknown')
            payload = message.get('payload', {})
            retry_count = message.get('retry_count', 0)
            max_retries = message.get('max_retries', 3)

            logger.info(
                f"Received task: {task_id} | Type: {task_type} | "
                f"Retry: {retry_count}/{max_retries}"
            )

            handler = self.task_handlers.get(task_type)

            if handler is None:
                logger.warning(
                    f"No handler registered for task type: {task_type}. "
                    f"Rejecting message."
                )
                channel.basic_nack(
                    delivery_tag=method.delivery_tag, requeue=False
                )
                return

            # Execute the handler
            start_time = time.time()
            result = handler(task_id, payload)
            elapsed = time.time() - start_time

            logger.info(
                f"Task {task_id} completed in {elapsed:.3f}s | "
                f"Result: {result}"
            )

            # Acknowledge the message
            channel.basic_ack(delivery_tag=method.delivery_tag)

        except json.JSONDecodeError as e:
            logger.error(f"Failed to decode message body: {e}")
            channel.basic_nack(
                delivery_tag=method.delivery_tag, requeue=False
            )

        except Exception as e:
            logger.error(f"Error processing task {task_id}: {e}", exc_info=True)
            self._handle_failure(channel, method, properties, body, e)

    def _handle_failure(self, channel, method, properties, body, error):
        """Handle task processing failure with retry logic."""
        try:
            message = json.loads(body)
            retry_count = message.get('retry_count', 0)
            max_retries = message.get('max_retries', 3)

            if retry_count < max_retries:
                # Retry: republish with incremented retry count
                message['retry_count'] = retry_count + 1
                message['last_error'] = str(error)
                message['last_retry_at'] = datetime.utcnow().isoformat()

                updated_properties = pika.BasicProperties(
                    delivery_mode=2,
                    content_type='application/json',
                    correlation_id=properties.correlation_id,
                    headers={
                        'retry_count': message['retry_count'],
                        'original_task_type': message.get('task_type', 'unknown'),
                    },
                )

                # Exponential backoff delay via TTL on a temporary queue
                delay_ms = (2 ** retry_count) * 1000  # 1s, 2s, 4s...
                delay_queue = f"{self.queue_name}_delay_{delay_ms}"
                channel.queue_declare(
                    queue=delay_queue,
                    durable=True,
                    arguments={
                        'x-message-ttl': delay_ms,
                        'x-dead-letter-exchange': self.exchange_name,
                        'x-dead-letter-routing-key': self.routing_key,
                    },
                )

                channel.basic_publish(
                    exchange='',
                    routing_key=delay_queue,
                    body=json.dumps(message),
                    properties=updated_properties,
                )

                logger.info(
                    f"Task {message.get('task_id')} scheduled for retry "
                    f"{message['retry_count']}/{max_retries} after {delay_ms}ms"
                )

                channel.basic_ack(delivery_tag=method.delivery_tag)
            else:
                # Max retries exceeded, send to dead letter queue
                logger.error(
                    f"Task {message.get('task_id')} exceeded max retries. "
                    f"Sending to dead letter queue."
                )
                channel.basic_nack(
                    delivery_tag=method.delivery_tag, requeue=False
                )

        except Exception as retry_error:
            logger.error(
                f"Error during failure handling: {retry_error}", exc_info=True
            )
            channel.basic_nack(
                delivery_tag=method.delivery_tag, requeue=False
            )

    def start_consuming(self):
        """Start consuming messages from the queue."""
        self.ensure_connection()
        self._consuming = True

        self.channel.basic_consume(
            queue=self.queue_name,
            on_message_callback=self._on_message,
            auto_ack=False,
        )

        logger.info(f"Consumer started. Waiting for tasks on '{self.queue_name}'...")

        try:
            self.channel.start_consuming()
        except KeyboardInterrupt:
            logger.info("Consumer interrupted by user.")
            self.stop_consuming()
        except pika.exceptions.ConnectionClosedByBroker:
            logger.error("Connection closed by broker. Attempting to reconnect...")
            self._reconnect_and_consume()
        except pika.exceptions.AMQPChannelError as e:
            logger.error(f"Channel error: {e}. Stopping consumer.")
            self.stop_consuming()
        except pika.exceptions.AMQPConnectionError:
            logger.error("Connection lost. Attempting to reconnect...")
            self._reconnect_and_consume()

    def _reconnect_and_consume(self):
        """Reconnect and resume consuming with backoff."""
        retry_delay = 5
        max_delay = 60

        while self._consuming:
            try:
                logger.info(f"Reconnecting in {retry_delay}s...")
                time.sleep(retry_delay)
                self.connect()
                self.setup()
                self.start_consuming()
                break
            except Exception as e:
                logger.error(f"Reconnection failed: {e}")
                retry_delay = min(retry_delay * 2, max_delay)

    def stop_consuming(self):
        """Stop consuming and close connection."""
        self._consuming = False
        if self.channel and self.channel.is_open:
            self.channel.stop_consuming()
        self.close()
        logger.info("Consumer stopped.")


class TaskProcessor:
    """High-level interface for the distributed task processing system."""

    def __init__(
        self,
        host: str = 'localhost',
        port: int = 5672,
        username: str = 'guest',
        password: str = 'guest',
        queue_name: str = 'task_queue',
        exchange_name: str = 'task_exchange',
        routing_key: str = 'task',
    ):
        self.connection_kwargs = {
            'host': host,
            'port': port,
            'username': username,
            'password': password,
        }
        self.queue_name = queue_name
        self.exchange_name = exchange_name
        self.routing_key = routing_key

    def create_publisher(self) -> TaskPublisher:
        """Create and set up a task publisher."""
        publisher = TaskPublisher(
            queue_name=self.queue_name,
            exchange_name=self.exchange_name,
            routing_key=self.routing_key,
            **self.connection_kwargs,
        )
        publisher.connect()
        publisher.setup()
        return publisher

    def create_consumer(self, prefetch_count: int = 1) -> TaskConsumer:
        """Create and set up a task consumer."""
        consumer = TaskConsumer(
            queue_name=self.queue_name,
            exchange_name=self.exchange_name,
            routing_key=self.routing_key,
            prefetch_count=prefetch_count,
            **self.connection_kwargs,
        )
        consumer.connect()
        consumer.setup()
        return consumer


