def run_publisher():
    """Run the publisher to send sample tasks."""
    processor = TaskProcessor(
        host='localhost',
        port=5672,
        queue_name='task_queue',
        exchange_name='task_exchange',
        routing_key='task',
    )

    publisher = processor.create_publisher()

    try:
        # Publish individual tasks
        task_id_1 = publisher.publish_task(
            task_type='send_email',
            payload={
                'recipient': 'user@example.com',
                'subject': 'Welcome!',
                'body': 'Welcome to our platform.',
            },
            priority=5,
        )
        print(f"Published email task: {task_id_1}")

        task_id_2 = publisher.publish_task(
            task_type='process_data',
            payload={
                'dataset': 'user_analytics_2024',
                'operation': 'aggregate',
                'filters': {'date_range': '2024-01-01/2024-12-31'},
            },
            priority=3,
        )
        print(f"Published data processing task: {task_id_2}")

        task_id_3 = publisher.publish_task(
            task_type='send_notification',
            payload={
                'user_id': 'user_12345',
                'message': 'Your report is ready!',
                'channel': 'push',
            },
            priority=7,
        )
        print(f"Published notification task: {task_id_3}")

        # Publish a batch of tasks
        batch_tasks = [
            {
                'task_type': 'send_email',
                'payload': {
                    'recipient': f'user{i}@example.com',
                    'subject': f'Batch email #{i}',
                    'body': f'This is batch email number {i}.',
                },
                'priority': 2,
            }
            for i in range(5)
        ]

        batch_ids = publisher.publish_batch(batch_tasks)
        print(f"Published batch of {len(batch_ids)} tasks: {batch_ids}")

    finally:
        publisher.close()


def run_consumer():
    """Run the consumer to process tasks."""
    processor = TaskProcessor(
        host='localhost',
        port=5672,
        queue_name='task_queue',
        exchange_name='task_exchange',
        routing_key='task',
    )

    consumer = processor.create_consumer(prefetch_count=3)

    # Register task handlers
    consumer.register_handler('send_email', handle_email_task)
    consumer.register_handler('process_data', handle_data_processing_task)
    consumer.register_handler('send_notification', handle_notification_task)

    # Start consuming (blocking)
    consumer.start_consuming()


